using ModelContextProtocol.Server;
using System.ComponentModel;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint by path.")]
    public async Task<string> FetchApi(
        [Description("The API URL to fetch (e.g. https://api.example.com/data)")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching API: {Url}", url);

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Received {Length} chars from {Url}", content.Length, url);

        return content;
    }
}

